/**
 * PixelArt image model IDs.
 */
export type PixelArtImageModelId =
  | 'pixelart-v1'
  | 'pixelart-v2'
  | 'pixelart-hd'
  | (string & {});

// Maximum number of images that can be generated in a single API call per model.
export const modelMaxImagesPerCall: Record<string, number> = {
  'pixelart-v1': 4,
  'pixelart-v2': 4,
  'pixelart-hd': 1,
};

/**
 * PixelArt-specific image generation options passed via providerOptions.
 *
 * @example
 * ```ts
 * await generateImage({
 *   model: pixelart.image('pixelart-v2'),
 *   prompt: 'A hero in a dungeon',
 *   providerOptions: {
 *     pixelart: {
 *       style: '8bit',
 *       pixelDensity: 4,
 *     },
 *   },
 * });
 * ```
 */
export interface PixelArtImageModelOptions {
  /**
   * The art style to apply to the generated image.
   * - `"pixel"`: Classic pixel art style.
   * - `"retro"`: Retro-inspired style with dithering and limited color palette.
   * - `"8bit"`: Strict 8-bit game aesthetic.
   */
  style?: 'pixel' | 'retro' | '8bit';

  /**
   * Pixel density multiplier. Higher values produce finer pixel grids.
   * Typical range: 1–8. Defaults to 1 when omitted.
   */
  pixelDensity?: number;
}

