import fs from 'node:fs';

import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it, vi } from 'vitest';
import { createPixelArt } from '../pixelart-provider';
import { PixelArtImageModel } from './pixelart-image-model';

vi.mock('../version', () => ({
  VERSION: '0.0.0-test',
}));

const prompt = 'A hero in a pixel art dungeon';

const provider = createPixelArt({ apiKey: 'test-api-key' });
const model = provider.image('pixelart-v2');

const server = createTestServer({
  'https://api.pixelart.ai/v1/images/generations': {},
});

function prepareJsonFixtureResponse(
  filename: string,
  headers?: Record<string, string>,
) {
  server.urls[
    'https://api.pixelart.ai/v1/images/generations'
  ].response = {
    type: 'json-value',
    headers,
    body: JSON.parse(
      fs.readFileSync(`src/image/__fixtures__/${filename}.json`, 'utf8'),
    ),
  };
}

describe('constructor', () => {
  it('should expose provider and modelId', () => {
    expect(model.provider).toBe('pixelart.image');
    expect(model.modelId).toBe('pixelart-v2');
    expect(model.specificationVersion).toBe('v3');
  });

  it('should return correct maxImagesPerCall for known models', () => {
    expect(provider.image('pixelart-v1').maxImagesPerCall).toBe(4);
    expect(provider.image('pixelart-v2').maxImagesPerCall).toBe(4);
    expect(provider.image('pixelart-hd').maxImagesPerCall).toBe(1);
  });

  it('should default maxImagesPerCall to 1 for unknown models', () => {
    expect(provider.image('unknown-model').maxImagesPerCall).toBe(1);
  });
});

describe('doGenerate', () => {
  it('should send the correct request body', async () => {
    prepareJsonFixtureResponse('pixelart-image');

    await model.doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 1,
      size: '512x512',
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
    });

    expect(await server.calls[0].requestBodyJson).toStrictEqual({
      model: 'pixelart-v2',
      prompt,
      n: 1,
      size: '512x512',
    });
  });

  it('should include style when provided via providerOptions', async () => {
    prepareJsonFixtureResponse('pixelart-image');

    await model.doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 1,
      size: '512x512',
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: { pixelart: { style: 'pixel' } },
    });

    expect(await server.calls[0].requestBodyJson).toStrictEqual({
      model: 'pixelart-v2',
      prompt,
      n: 1,
      size: '512x512',
      style: 'pixel',
    });
  });

  it('should include pixel_density when provided via providerOptions', async () => {
    prepareJsonFixtureResponse('pixelart-image');

    await model.doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 1,
      size: '256x256',
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: { pixelart: { pixelDensity: 4 } },
    });

    expect(await server.calls[0].requestBodyJson).toStrictEqual({
      model: 'pixelart-v2',
      prompt,
      n: 1,
      size: '256x256',
      pixel_density: 4,
    });
  });

  it('should include both style and pixel_density when both are provided', async () => {
    prepareJsonFixtureResponse('pixelart-image');

    await model.doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 2,
      size: '512x512',
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: { pixelart: { style: '8bit', pixelDensity: 2 } },
    });

    expect(await server.calls[0].requestBodyJson).toStrictEqual({
      model: 'pixelart-v2',
      prompt,
      n: 2,
      size: '512x512',
      style: '8bit',
      pixel_density: 2,
    });
  });

  it('should pass the authorization header', async () => {
    prepareJsonFixtureResponse('pixelart-image');

    await model.doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
    });

    expect(server.calls[0].requestHeaders['authorization']).toBe(
      'Bearer test-api-key',
    );
  });

  it('should include custom provider headers', async () => {
    prepareJsonFixtureResponse('pixelart-image');

    const customProvider = createPixelArt({
      apiKey: 'test-api-key',
      headers: { 'X-Custom-Header': 'custom-value' },
    });

    await customProvider.image('pixelart-v1').doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
    });

    expect(server.calls[0].requestHeaders['x-custom-header']).toBe(
      'custom-value',
